from abc import ABC, abstractmethod

class PricingStrategy(ABC):
    @abstractmethod
    def calculate(self, base_price: float) -> float: ...

class RegularPricing(PricingStrategy):
    def calculate(self, base_price: float) -> float:
        return base_price

class PremiumPricing(PricingStrategy):
    def calculate(self, base_price: float) -> float:
        return base_price * 0.9

class VIPPricing(PricingStrategy):
    def calculate(self, base_price: float) -> float:
        return base_price * 0.8

class EmployeePricing(PricingStrategy):
    def calculate(self, base_price: float) -> float:
        return base_price * 0.7

# Usage:
strategies = {
    'regular': RegularPricing(),
    'premium': PremiumPricing(),
    'vip': VIPPricing(),
    'employee': EmployeePricing(),
}

def calculate_price(base_price: float, customer_type: str) -> float:
    strategy = strategies.get(customer_type)
    if not strategy:
        raise ValueError(f"Unknown customer type: {customer_type}")
    return strategy.calculate(base_price)
```
New pricing tiers can be added without modifying existing code (Open/Closed Principle).

