from dataclasses import dataclass

ABSOLUTE_ZERO_C = -273.15

@dataclass
class Temperature:
    celsius: float

    def __post_init__(self) -> None:
        if self.celsius < ABSOLUTE_ZERO_C:
            raise ValueError(
                f"Temperature {self.celsius}°C is below absolute zero ({ABSOLUTE_ZERO_C}°C)"
            )

    @property
    def fahrenheit(self) -> float:
        return self.celsius * 9 / 5 + 32

    @property
    def kelvin(self) -> float:
        return self.celsius - ABSOLUTE_ZERO_C

    def __str__(self) -> str:
        return f"{self.celsius:.1f}°C ({self.fahrenheit:.1f}°F, {self.kelvin:.1f}K)"

# Usage:
t = Temperature(100)
print(t)            # 100.0°C (212.0°F, 373.1K)
print(t.kelvin)     # 373.15
# Temperature(-300)  # raises ValueError
